import{_ as e,c as i,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Changelog: История версий и изменения функций | Agent App Factory","description":"Узнайте об истории обновлений Agent App Factory, изменениях функций, исправлениях ошибок и значительных улучшениях. Эта страница содержит подробную историю изменений начиная с версии 1.0.0, включая основные функции и улучшения: 7-этапная система конвейера, планировщик Sisyphus, управление правами, оптимизация контекста и стратегии обработки ошибок.","frontmatter":{"title":"Changelog: История версий и изменения функций | Agent App Factory","sidebarTitle":"Changelog","subtitle":"Changelog: История версий и изменения функций | Agent App Factory","description":"Узнайте об истории обновлений Agent App Factory, изменениях функций, исправлениях ошибок и значительных улучшениях. Эта страница содержит подробную историю изменений начиная с версии 1.0.0, включая основные функции и улучшения: 7-этапная система конвейера, планировщик Sisyphus, управление правами, оптимизация контекста и стратегии обработки ошибок.","tags":["Changelog","История версий"],"prerequisite":[],"order":250},"headers":[],"relativePath":"ru/hyz1992/agent-app-factory/changelog/release-notes/index.md","filePath":"ru/hyz1992/agent-app-factory/changelog/release-notes/index.md"}'),l={name:"ru/hyz1992/agent-app-factory/changelog/release-notes/index.md"};function o(n,t,d,c,s,g){return r(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>Эта страница содержит историю обновлений Agent App Factory, включая новые функции, улучшения, исправления ошибок и критические изменения.</p><p>Формат следует спецификации <a href="https://keepachangelog.com/ru/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, номера версий следуют <a href="https://semver.org/lang/ru/" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="_1-0-0-2024-01-29" tabindex="-1">[1.0.0] - 2024-01-29 <a class="header-anchor" href="#_1-0-0-2024-01-29" aria-label="Permalink to &quot;[1.0.0] - 2024-01-29&quot;">​</a></h2><h3 id="добавлено" tabindex="-1">Добавлено <a class="header-anchor" href="#добавлено" aria-label="Permalink to &quot;Добавлено&quot;">​</a></h3><p><strong>Основные функции</strong></p><ul><li><p><strong>7-этапная система конвейера</strong>: Полный автоматизированный процесс от идеи до работающего приложения</p><ul><li>Bootstrap - Структурирование продукта (input/idea.md)</li><li>PRD - Генерация документа требований продукта (artifacts/prd/prd.md)</li><li>UI - Проектирование структуры UI и интерактивного прототипа (artifacts/ui/)</li><li>Tech - Проектирование технической архитектуры и модели данных Prisma (artifacts/tech/)</li><li>Code - Генерация кода фронтенда и бэкенда (artifacts/backend/, artifacts/client/)</li><li>Validation - Проверка качества кода (artifacts/validation/report.md)</li><li>Preview - Генерация руководства по развертыванию (artifacts/preview/README.md)</li></ul></li><li><p><strong>Планировщик Sisyphus</strong>: Основной компонент управления конвейером</p><ul><li>Последовательное выполнение этапов, определенных в pipeline.yaml</li><li>Проверка входных/выходных данных и условий выхода каждого этапа</li><li>Поддержка состояния конвейера (.factory/state.json)</li><li>Выполнение проверок прав доступа, предотвращение несанкционированного доступа</li><li>Обработка исключений в соответствии со стратегиями</li><li>Пауза на каждом чекпоинте, ожидание подтверждения перед продолжением</li></ul></li></ul><p><strong>CLI инструменты</strong></p><ul><li><code>factory init</code> - Инициализация Factory проекта</li><li><code>factory run [stage]</code> - Запуск конвейера (с текущего или указанного этапа)</li><li><code>factory continue</code> - Продолжение выполнения в новой сессии (экономия токенов)</li><li><code>factory status</code> - Просмотр текущего состояния проекта</li><li><code>factory list</code> - Список всех Factory проектов</li><li><code>factory reset</code> - Сброс состояния текущего проекта</li></ul><p><strong>Права доступа и безопасность</strong></p><ul><li><strong>Матрица возможностей</strong> (capability.matrix.md): Определение строгих прав доступа для каждого агента <ul><li>Каждый агент имеет доступ только к авторизованным директориям</li><li>Несанкционированные записи перемещаются в artifacts/_untrusted/</li><li>Автоматическая пауза конвейера при неудаче, ожидание вмешательства</li></ul></li></ul><p><strong>Оптимизация контекста</strong></p><ul><li><strong>Выполнение по сессиям</strong>: Каждый этап выполняется в новой сессии <ul><li>Избежание накопления контекста, экономия токенов</li><li>Поддержка возобновления после прерывания</li><li>Применимо ко всем AI-ассистентам (Claude Code, OpenCode, Cursor)</li></ul></li></ul><p><strong>Стратегии обработки ошибок</strong></p><ul><li>Механизм автоматических повторных попыток: Разрешен один повтор на этап</li><li>Архивирование неудач: Неудачные артефакты перемещаются в artifacts/_failed/</li><li>Механизм отката: Откат к последнему успешному чекпоинту</li><li>Вмешательство человека: Пауза после двух последовательных неудач</li></ul><p><strong>Обеспечение качества</strong></p><ul><li><p><strong>Стандарты кода</strong> (code-standards.md)</p><ul><li>Спецификации кодирования и лучшие практики TypeScript</li><li>Структура файлов и соглашения об именовании</li><li>Требования к комментариям и документации</li><li>Спецификации сообщений коммитов Git (Conventional Commits)</li></ul></li><li><p><strong>Стандарты кодов ошибок</strong> (error-codes.md)</p><ul><li>Унифицированная структура кодов ошибок: [MODULE]<em>[ERROR_TYPE]</em>[SPECIFIC]</li><li>Стандартные типы ошибок: VALIDATION, NOT_FOUND, FORBIDDEN, CONFLICT, INTERNAL_ERROR</li><li>Сопоставление кодов ошибок фронтенда и бэкенда и пользовательские сообщения</li></ul></li></ul><p><strong>Управление Changelog</strong></p><ul><li>Следование формату Keep a Changelog</li><li>Интеграция с Conventional Commits</li><li>Поддержка инструментов автоматизации: conventional-changelog-cli, release-it</li></ul><p><strong>Шаблоны конфигурации</strong></p><ul><li>Конфигурация CI/CD (GitHub Actions)</li><li>Конфигурация Git Hooks (Husky)</li></ul><p><strong>Особенности генерируемых приложений</strong></p><ul><li>Полный код фронтенда и бэкенда (Express + Prisma + React Native)</li><li>Модульные и интеграционные тесты (Vitest + Jest)</li><li>Документация API (Swagger/OpenAPI)</li><li>Сид-данные базы данных</li><li>Конфигурация развертывания Docker</li><li>Обработка ошибок и мониторинг журналов</li><li>Оптимизация производительности и проверки безопасности</li></ul><h3 id="улучшено" tabindex="-1">Улучшено <a class="header-anchor" href="#улучшено" aria-label="Permalink to &quot;Улучшено&quot;">​</a></h3><p><strong>MVP-фокус</strong></p><ul><li>Четкое перечисление невключенных целей (Non-Goals) для предотвращения разрастания проекта</li><li>Ограничение количества страниц до 3</li><li>Фокус на основных функциях, избегание избыточного проектирования</li></ul><p><strong>Разделение ответственности</strong></p><ul><li>Каждый агент отвечает только за свою область, не выходит за рамки полномочий</li><li>PRD не содержит технических деталей, Tech не затрагивает проектирование UI</li><li>Code Agent строго следует UI Schema и Tech дизайну при реализации</li></ul><p><strong>Верифицируемость</strong></p><ul><li>Каждый этап определяет четкие критерии выхода (exit_criteria)</li><li>Все функции могут быть протестированы и запущены локально</li><li>Артефакты должны быть структурированы и могут быть использованы последующими этапами</li></ul><h3 id="технологическии-стек" tabindex="-1">Технологический стек <a class="header-anchor" href="#технологическии-стек" aria-label="Permalink to &quot;Технологический стек&quot;">​</a></h3><p><strong>CLI инструменты</strong></p><ul><li>Node.js &gt;= 16.0.0</li><li>Commander.js - фреймворк командной строки</li><li>Chalk - цветной вывод в терминал</li><li>Ora - индикатор прогресса</li><li>Inquirer - интерактивная командная строка</li><li>fs-extra - операции файловой системы</li><li>YAML - парсер YAML</li></ul><p><strong>Генерируемые приложения</strong></p><ul><li>Бэкенд: Node.js + Express + Prisma + TypeScript + Vitest</li><li>Фронтенд: React Native + Expo + TypeScript + Jest + React Testing Library</li><li>Развертывание: Docker + GitHub Actions</li></ul><h3 id="зависимости" tabindex="-1">Зависимости <a class="header-anchor" href="#зависимости" aria-label="Permalink to &quot;Зависимости&quot;">​</a></h3><ul><li><code>chalk@^4.1.2</code> - стили терминала</li><li><code>commander@^11.0.0</code> - парсинг аргументов командной строки</li><li><code>fs-extra@^11.1.1</code> - расширения файловой системы</li><li><code>inquirer@^8.2.5</code> - интерактивная командная строка</li><li><code>ora@^5.4.1</code> - элегантный загрузчик терминала</li><li><code>yaml@^2.3.4</code> - парсинг и сериализация YAML</li></ul><h2 id="заметки-о-версиях" tabindex="-1">Заметки о версиях <a class="header-anchor" href="#заметки-о-версиях" aria-label="Permalink to &quot;Заметки о версиях&quot;">​</a></h2><h3 id="semantic-versioning" tabindex="-1">Semantic Versioning <a class="header-anchor" href="#semantic-versioning" aria-label="Permalink to &quot;Semantic Versioning&quot;">​</a></h3><p>Этот проект следует формату номеров версий <a href="https://semver.org/lang/ru/" target="_blank" rel="noreferrer">Semantic Versioning</a>: MAJOR.MINOR.PATCH</p><ul><li><strong>MAJOR</strong>: Несовместимые изменения API</li><li><strong>MINOR</strong>: Обратно совместимые добавления функций</li><li><strong>PATCH</strong>: Обратно совместимые исправления ошибок</li></ul><h3 id="типы-изменении" tabindex="-1">Типы изменений <a class="header-anchor" href="#типы-изменении" aria-label="Permalink to &quot;Типы изменений&quot;">​</a></h3><ul><li><strong>Добавлено</strong> (Added): Новые функции</li><li><strong>Изменено</strong> (Changed): Изменения существующих функций</li><li><strong>Устарело</strong> (Deprecated): Функции, которые скоро будут удалены</li><li><strong>Удалено</strong> (Removed): Удаленные функции</li><li><strong>Исправлено</strong> (Fixed): Исправления ошибок</li><li><strong>Безопасность</strong> (Security): Исправления безопасности</li></ul><h2 id="связанные-ресурсы" tabindex="-1">Связанные ресурсы <a class="header-anchor" href="#связанные-ресурсы" aria-label="Permalink to &quot;Связанные ресурсы&quot;">​</a></h2><ul><li><a href="https://github.com/hyz1992/agent-app-factory/releases" target="_blank" rel="noreferrer">GitHub Releases</a> - Официальная страница релизов</li><li><a href="https://github.com/hyz1992/agent-app-factory" target="_blank" rel="noreferrer">Репозиторий проекта</a> - Исходный код</li><li><a href="https://github.com/hyz1992/agent-app-factory/issues" target="_blank" rel="noreferrer">Issue Tracker</a> - Обратная связь и предложения</li><li><a href="https://github.com/hyz1992/agent-app-factory/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">Руководство по участию</a> - Как внести вклад</li></ul><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть исходный код</strong></summary><blockquote><p>Дата обновления: 2024-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>package.json</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/package.json" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-52</td></tr><tr><td>CLI entry</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/bin/factory.js" target="_blank" rel="noreferrer"><code>cli/bin/factory.js</code></a></td><td>1-123</td></tr><tr><td>init command</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/init.js" target="_blank" rel="noreferrer"><code>cli/commands/init.js</code></a></td><td>1-427</td></tr><tr><td>run command</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/run.js" target="_blank" rel="noreferrer"><code>cli/commands/run.js</code></a></td><td>1-294</td></tr><tr><td>continue command</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/continue.js" target="_blank" rel="noreferrer"><code>cli/commands/continue.js</code></a></td><td>1-87</td></tr><tr><td>pipeline definition</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>1-87</td></tr><tr><td>orchestrator definition</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-301</td></tr><tr><td>capability matrix</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/capability.matrix.md" target="_blank" rel="noreferrer"><code>policies/capability.matrix.md</code></a></td><td>1-44</td></tr><tr><td>failure policy</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/failure.policy.md" target="_blank" rel="noreferrer"><code>policies/failure.policy.md</code></a></td><td>1-200</td></tr><tr><td>code standards</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/code-standards.md" target="_blank" rel="noreferrer"><code>policies/code-standards.md</code></a></td><td>1-287</td></tr><tr><td>error codes</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/error-codes.md" target="_blank" rel="noreferrer"><code>policies/error-codes.md</code></a></td><td>1-134</td></tr><tr><td>changelog policy</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/changelog.md" target="_blank" rel="noreferrer"><code>policies/changelog.md</code></a></td><td>1-87</td></tr></tbody></table><p><strong>Ключевая информация о версиях</strong>:</p><ul><li><code>version = &quot;1.0.0&quot;</code>: Начальная версия релиза</li><li><code>engines.node = &quot;&gt;=16.0.0&quot;</code>: Минимальная требуемая версия Node.js</li></ul><p><strong>Версии зависимостей</strong>:</p><ul><li><code>chalk@^4.1.2</code>: Стили терминала</li><li><code>commander@^11.0.0</code>: Парсинг аргументов командной строки</li><li><code>fs-extra@^11.1.1</code>: Расширения файловой системы</li><li><code>inquirer@^8.2.5</code>: Интерактивная командная строка</li><li><code>ora@^5.4.1</code>: Элегантный загрузчик терминала</li><li><code>yaml@^2.3.4</code>: Парсинг и сериализация YAML</li></ul></details>',48)])])}const u=e(l,[["render",o]]);export{h as __pageData,u as default};
